import redis

def execute_lua_script():
    # Connect to Redis
    r = redis.StrictRedis(host='localhost', port=6379, db=0)

    # Get Lua script from user input
    lua_script_code = input("Enter the Lua script code: ")

    # Get parameters for the Lua script from user input
    num_params = int(input("Number of parameters for the Lua script: "))
    params = [input(f"Parameter {i+1}: ") for i in range(num_params)]

    # Execute the Lua script with user-provided parameters
    result = r.eval(lua_script_code, 0, *params)

    print("Script executed successfully. Result:", result)

if __name__ == "__main__":
    execute_lua_script()